#!/usr/bin/env bash
# =========================================================
# سكربت لرفع كتاب UNL (book/unl-book.pdf) مباشرة إلى مستودعك
# على GitHub عبر الـ API، بدون الحاجة لرفعه يدويًا من الموقع.
#
# طريقة الاستخدام:
# 1) عدّل القيم الثلاث التالية أسفل (GITHUB_TOKEN, OWNER, REPO).
# 2) شغّل هذا الملف في أي طرفية فيها bash و curl (لينكس/ماك/
#    Git Bash على ويندوز/ Codespaces/ Termux).
#      bash upload_book_to_github.sh
# 3) بعد نجاحه، سيظهر الملف مباشرة داخل مستودعك في المسار:
#      book/unl-book.pdf
#
# كيف تحصل على GITHUB_TOKEN:
#   اذهب إلى: https://github.com/settings/tokens
#   -> Generate new token (classic) -> فعّل صلاحية "repo" فقط
#   -> انسخ التوكن وضعه أسفل بدل YOUR_TOKEN_HERE
# =========================================================

GITHUB_TOKEN="YOUR_TOKEN_HERE"     # ضع التوكن الخاص بك هنا
OWNER="brahimkha959-spec"       # اسم المستخدم أو المنظمة في GitHub
REPO="Unl-studio-"              # اسم المستودع
BRANCH="main"                      # اسم الفرع (غيّره إلى master إذا لزم)
FILE_PATH="book/unl-book.pdf"      # المسار داخل المستودع (لا تغيّره)

# ---------------------------------------------------------
# لا حاجة لتعديل أي شيء أسفل هذا السطر
# ---------------------------------------------------------

set -e

if [ "$GITHUB_TOKEN" = "YOUR_TOKEN_HERE" ]; then
  echo "❌ الرجاء وضع التوكن الخاص بك في GITHUB_TOKEN أعلى الملف أولاً."
  exit 1
fi

API_URL="https://api.github.com/repos/${OWNER}/${REPO}/contents/${FILE_PATH}"

echo "🔎 التحقق مما إذا كان الملف موجودًا مسبقًا في المستودع..."
EXISTING_SHA=$(curl -s -H "Authorization: token ${GITHUB_TOKEN}" "${API_URL}?ref=${BRANCH}" | grep -m1 '"sha"' | sed -E 's/.*"sha": *"([^"]+)".*/\1/')

BASE64_CONTENT="
